import requests
import json
import sys
from typing import List, Dict, Optional
from requests.auth import HTTPBasicAuth


class RabbitMQManager:
    def __init__(self, host: str = 'localhost', port: int = 15672, 
                 username: str = 'guest', password: str = 'guest'):
        self.base_url = f'http://{host}:{port}/api'
        self.auth = HTTPBasicAuth(username, password)
        self.session = requests.Session()
        self.session.auth = self.auth
        
    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> requests.Response:
        url = f'{self.base_url}/{endpoint}'
        headers = {'Content-Type': 'application/json'}
        
        try:
            if method == 'GET':
                response = self.session.get(url, headers=headers)
            elif method == 'PUT':
                response = self.session.put(url, headers=headers, json=data if data else {})
            elif method == 'POST':
                response = self.session.post(url, headers=headers, json=data)
            elif method == 'DELETE':
                response = self.session.delete(url, headers=headers)
            else:
                raise ValueError(f'Unsupported HTTP method: {method}')
            
            return response
        except requests.exceptions.RequestException as e:
            print(f'Error making request to {url}: {e}')
            raise
    
    def create_vhost(self, vhost_name: str) -> bool:
        print(f'Creating virtual host: {vhost_name}')
        response = self._make_request('PUT', f'vhosts/{vhost_name}')
        
        if response.status_code in [201, 204]:
            print(f'Virtual host "{vhost_name}" created successfully')
            return True
        else:
            print(f'Failed to create virtual host "{vhost_name}": {response.status_code} - {response.text}')
            return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        print(f'Deleting virtual host: {vhost_name}')
        response = self._make_request('DELETE', f'vhosts/{vhost_name}')
        
        if response.status_code == 204:
            print(f'Virtual host "{vhost_name}" deleted successfully')
            return True
        else:
            print(f'Failed to delete virtual host "{vhost_name}": {response.status_code} - {response.text}')
            return False
    
    def list_vhosts(self) -> List[Dict]:
        response = self._make_request('GET', 'vhosts')
        
        if response.status_code == 200:
            vhosts = response.json()
            print(f'Found {len(vhosts)} virtual hosts:')
            for vhost in vhosts:
                print(f'  - {vhost["name"]}')
            return vhosts
        else:
            print(f'Failed to list virtual hosts: {response.status_code}')
            return []
    
    def create_user(self, username: str, password: str, tags: str = '') -> bool:
        print(f'Creating user: {username}')
        data = {
            'password': password,
            'tags': tags
        }
        response = self._make_request('PUT', f'users/{username}', data)
        
        if response.status_code in [201, 204]:
            print(f'User "{username}" created successfully with tags: {tags}')
            return True
        else:
            print(f'Failed to create user "{username}": {response.status_code} - {response.text}')
            return False
    
    def delete_user(self, username: str) -> bool:
        print(f'Deleting user: {username}')
        response = self._make_request('DELETE', f'users/{username}')
        
        if response.status_code == 204:
            print(f'User "{username}" deleted successfully')
            return True
        else:
            print(f'Failed to delete user "{username}": {response.status_code} - {response.text}')
            return False
    
    def list_users(self) -> List[Dict]:
        response = self._make_request('GET', 'users')
        
        if response.status_code == 200:
            users = response.json()
            print(f'Found {len(users)} users:')
            for user in users:
                print(f'  - {user["name"]} (tags: {user.get("tags", "")})')
            return users
        else:
            print(f'Failed to list users: {response.status_code}')
            return []
    
    def set_permissions(self, username: str, vhost_name: str, 
                       configure: str = '.*', write: str = '.*', read: str = '.*') -> bool:
        print(f'Setting permissions for user "{username}" on vhost "{vhost_name}"')
        data = {
            'configure': configure,
            'write': write,
            'read': read
        }
        response = self._make_request('PUT', f'permissions/{vhost_name}/{username}', data)
        
        if response.status_code in [201, 204]:
            print(f'Permissions set successfully:')
            print(f'  Configure: {configure}')
            print(f'  Write: {write}')
            print(f'  Read: {read}')
            return True
        else:
            print(f'Failed to set permissions: {response.status_code} - {response.text}')
            return False
    
    def get_permissions(self, username: str, vhost_name: str) -> Optional[Dict]:
        response = self._make_request('GET', f'permissions/{vhost_name}/{username}')
        
        if response.status_code == 200:
            perms = response.json()
            print(f'Permissions for "{username}" on "{vhost_name}":')
            print(f'  Configure: {perms.get("configure", "N/A")}')
            print(f'  Write: {perms.get("write", "N/A")}')
            print(f'  Read: {perms.get("read", "N/A")}')
            return perms
        else:
            print(f'Failed to get permissions: {response.status_code}')
            return None
    
    def delete_permissions(self, username: str, vhost_name: str) -> bool:
        print(f'Deleting permissions for user "{username}" on vhost "{vhost_name}"')
        response = self._make_request('DELETE', f'permissions/{vhost_name}/{username}')
        
        if response.status_code == 204:
            print(f'Permissions deleted successfully')
            return True
        else:
            print(f'Failed to delete permissions: {response.status_code}')
            return False
    
    def list_vhost_permissions(self, vhost_name: str) -> List[Dict]:
        response = self._make_request('GET', f'vhosts/{vhost_name}/permissions')
        
        if response.status_code == 200:
            perms = response.json()
            print(f'Permissions for vhost "{vhost_name}":')
            for perm in perms:
                print(f'  User: {perm["user"]}')
                print(f'    Configure: {perm.get("configure", "N/A")}')
                print(f'    Write: {perm.get("write", "N/A")}')
                print(f'    Read: {perm.get("read", "N/A")}')
            return perms
        else:
            print(f'Failed to list vhost permissions: {response.status_code}')
            return []
    
    def setup_multi_tenant_environment(self, tenants: List[Dict]) -> bool:
        print('\n=== Setting up Multi-Tenant RabbitMQ Environment ===\n')
        
        success = True
        
        for tenant in tenants:
            tenant_name = tenant['name']
            vhost_name = tenant.get('vhost', f'/tenant_{tenant_name}')
            users = tenant.get('users', [])
            
            print(f'\n--- Configuring tenant: {tenant_name} ---')
            
            if not self.create_vhost(vhost_name):
                success = False
                continue
            
            for user_config in users:
                username = user_config['username']
                password = user_config['password']
                tags = user_config.get('tags', '')
                permissions = user_config.get('permissions', {})
                
                if not self.create_user(username, password, tags):
                    success = False
                    continue
                
                configure = permissions.get('configure', '.*')
                write = permissions.get('write', '.*')
                read = permissions.get('read', '.*')
                
                if not self.set_permissions(username, vhost_name, configure, write, read):
                    success = False
        
        print('\n=== Multi-Tenant Setup Complete ===\n')
        return success
    
    def get_cluster_overview(self) -> Optional[Dict]:
        response = self._make_request('GET', 'overview')
        
        if response.status_code == 200:
            overview = response.json()
            print('RabbitMQ Cluster Overview:')
            print(f'  RabbitMQ Version: {overview.get("rabbitmq_version", "N/A")}')
            print(f'  Erlang Version: {overview.get("erlang_version", "N/A")}')
            print(f'  Cluster Name: {overview.get("cluster_name", "N/A")}')
            return overview
        else:
            print(f'Failed to get cluster overview: {response.status_code}')
            return None


